import { Children, isValidElement, type ReactNode } from 'react';

import { isSlot } from '../../../../core/utils/is-slot.js';
import type {
  FilterFieldSuggestion,
  FlattenedSuggestionItem,
  GroupMetadata,
} from '../../suggestions/Suggestion.types.js';
import { SuggestionGroup } from '../../suggestions/SuggestionGroup.js';
import type { FilterFieldSuggestionGroup } from '../../suggestions/SuggestionGroup.types.js';
import { SuggestionGroupLabel } from '../../suggestions/SuggestionGroupLabel.js';
import {
  isFilterFieldSuggestion,
  isFilterFieldSuggestionGroup,
} from '../tree-node-guards.js';

/**
 * Flattens a suggestions array so that every suggestion — whether standalone or inside a group — becomes its own entry.
 * Group labels are emitted as separate `group-header` items.
 * Empty groups are omitted entirely.
 * The original array can contain:
 * - Data objects of type FilterFieldSuggestion and FilterFieldSuggestionGroup
 * - FilterField.SuggestionGroup and FilterField.SuggestionGroupLabel elements
 * @internal
 */
export function flattenSuggestions(
  items: (ReactNode | FilterFieldSuggestion | FilterFieldSuggestionGroup)[],
): {
  flattenedSuggestionItems: FlattenedSuggestionItem[];
  groupMetadata: GroupMetadata[];
} {
  const flattenedSuggestionItems: FlattenedSuggestionItem[] = [];
  const groupMetadata: GroupMetadata[] = [];
  // Skip empty headers (no label) for the first group. They would only render
  // a divider, which would be hidden for the first group, so we can skip it entirely.
  let isFirstGroup = true;

  for (let index = 0; index < items.length; index++) {
    const item = items[index];

    // Flatten ReactElements.
    if (isValidElement(item)) {
      // SuggestionGroup compound component.
      if (isSlot(item, SuggestionGroup)) {
        const {
          label,
          suggestions,
          children,
          id,
          'aria-label': ariaLabel,
        } = item.props;
        const groupId = id ?? `__group_${index}`;

        const childArray = Children.toArray(children);
        // We expect the label to always be the first child if present.
        // If present, we slice the array to not include the label in the suggestions.
        const labelSlot = isSlot(childArray[0], SuggestionGroupLabel)
          ? childArray[0]
          : undefined;
        const groupedSuggestionChildren = labelSlot
          ? childArray.slice(1)
          : childArray;

        const suggestionCount =
          (suggestions?.length ?? 0) + groupedSuggestionChildren.length;

        // Skip empty groups.
        if (suggestionCount === 0) {
          continue;
        }

        const hasLabel = labelSlot !== undefined || label !== undefined;
        const hasAriaLabel = ariaLabel !== undefined;
        const shouldAddHeader = hasLabel || hasAriaLabel || !isFirstGroup;
        isFirstGroup = false;

        // Add group header.
        if (shouldAddHeader) {
          if (labelSlot) {
            flattenedSuggestionItems.push({
              kind: 'group-header',
              label: labelSlot,
              groupId,
            });
            groupMetadata.push({ groupId, label: labelSlot });
          } else if (label) {
            flattenedSuggestionItems.push({
              kind: 'group-header',
              label,
              groupId,
            });
            groupMetadata.push({ groupId, label });
          } else {
            flattenedSuggestionItems.push({ kind: 'group-header', groupId });

            // If an aria-label is provided, still add it to groupMetadata so it
            // renders as a hidden <span> for screen-reader announcements.
            if (hasAriaLabel) {
              groupMetadata.push({ groupId, label: ariaLabel });
            }
          }
        }

        // Add individual suggestions from the suggestions prop.
        if (suggestions) {
          for (const s of suggestions) {
            flattenedSuggestionItems.push({
              kind: 'suggestion',
              data: s,
              groupId,
            });
          }
        }

        // Add individual suggestions from the children (FilterField.Suggestion).
        for (const child of groupedSuggestionChildren) {
          flattenedSuggestionItems.push({
            kind: 'react-node',
            node: child,
            groupId,
          });
        }

        continue;
      }

      // Add FilterField.Suggestion element.
      flattenedSuggestionItems.push({ kind: 'react-node', node: item });
      continue;
    }

    // Flatten FilterFieldSuggestionGroup object.
    if (isFilterFieldSuggestionGroup(item)) {
      const groupId = item.id ?? `__group_${index}`;

      // Skip empty groups entirely.
      if (!item.suggestions || item.suggestions.length === 0) {
        continue;
      }

      const hasLabel = item.label !== undefined;
      const hasAriaLabel = item['aria-label'] !== undefined;
      const shouldAddHeader = hasLabel || hasAriaLabel || !isFirstGroup;
      isFirstGroup = false;

      if (shouldAddHeader) {
        flattenedSuggestionItems.push({
          kind: 'group-header',
          label: item.label,
          groupId,
        });

        if (hasLabel || hasAriaLabel) {
          groupMetadata.push({
            groupId,
            label: item.label ?? item['aria-label'],
          });
        }
      }

      for (const s of item.suggestions) {
        flattenedSuggestionItems.push({ kind: 'suggestion', data: s, groupId });
      }

      continue;
    }

    // Add suggestion for FilterFieldSuggestion object.
    if (isFilterFieldSuggestion(item)) {
      flattenedSuggestionItems.push({ kind: 'suggestion', data: item });
    }
  }

  return { flattenedSuggestionItems, groupMetadata };
}
